# Dataroots QnA Bot — Agentic AI Academy, Day 1
#
# Single-file Modal app:
#   1. Builds a container image with headless Chromium.
#   2. Scrapes the Dataroots Notion doc + all subpages ONCE at image build time
#      (the result is baked into the image -> fast & deterministic at request time).
#   3. Exposes a GET endpoint that answers questions grounded strictly in that
#      knowledge base, using Gemini 2.5 Flash-Lite. If the answer isn't in the KB,
#      it returns the exact banana fallback (no hallucinations).
#
# Deploy:   modal deploy qna_bot.py
# Test:     curl --get --data-urlencode "query=What is dataroots?" <endpoint-url>
#
# Requires a Modal secret named "gemini" holding GEMINI_API_KEY:
#   modal secret create gemini GEMINI_API_KEY=<your-key>

import os
import modal

START_URL = "https://dataroots.notion.site/about-dataroots"
KB_PATH = "/kb.txt"  # where the scraped knowledge base is stored inside the image
MODEL = "gemini-2.5-flash-lite"

# Exact reply when the answer is not in the knowledge base (no guessing).
FALLBACK = (
    "Life's a wobbly unicycle ride on a banana peel, so embrace the chaos "
    "and you might just land on something surprisingly awesome. \U0001f34c"
)


def _scrape_all() -> None:
    """Crawl the Notion doc and its subpages, save combined text to KB_PATH.

    Runs at IMAGE BUILD time (see image.run_function below), so the knowledge
    base is captured once and frozen into the image. The brief guarantees the
    pages and URLs won't change, so a one-time scrape is safe.
    """
    import time

    from selenium import webdriver
    from selenium.webdriver.chrome.service import Service
    from selenium.webdriver.common.by import By
    from selenium.webdriver.support.ui import WebDriverWait
    from selenium.webdriver.support import expected_conditions as EC

    options = webdriver.ChromeOptions()
    options.binary_location = "/usr/bin/chromium"
    options.add_argument("--headless=new")
    options.add_argument("--no-sandbox")
    options.add_argument("--disable-dev-shm-usage")
    driver = webdriver.Chrome(service=Service("/usr/bin/chromedriver"), options=options)

    visited: set[str] = set()
    queue: list[str] = [START_URL]
    chunks: list[str] = []

    try:
        # Breadth-first crawl. Cap at 60 pages as a safety net.
        while queue and len(visited) < 60:
            url = queue.pop(0)
            if url in visited:
                continue
            visited.add(url)
            try:
                driver.get(url)
                WebDriverWait(driver, 20).until(
                    EC.presence_of_element_located(
                        (By.CLASS_NAME, "notion-page-content")
                    )
                )
                time.sleep(1.5)  # let lazy blocks finish rendering

                try:
                    heading = driver.find_element(By.CLASS_NAME, "layout-content").text
                except Exception:
                    heading = ""
                body = driver.find_element(By.CLASS_NAME, "notion-page-content").text
                chunks.append(f"## PAGE: {url}\n{heading}\n{body}")

                # Discover subpage links (same Notion workspace only).
                for a in driver.find_elements(By.CSS_SELECTOR, "a[href]"):
                    href = a.get_attribute("href") or ""
                    if "dataroots.notion.site" in href:
                        href = href.split("?")[0].split("#")[0].rstrip("/")
                        if href and href not in visited and href not in queue:
                            queue.append(href)
            except Exception as e:  # one bad page shouldn't kill the whole crawl
                print(f"[scrape] skipped {url}: {e}")
    finally:
        driver.quit()

    text = "\n\n".join(chunks)
    with open(KB_PATH, "w", encoding="utf-8") as f:
        f.write(text)
    print(f"[scrape] pages={len(visited)} chars={len(text)}")


image = (
    modal.Image.debian_slim(python_version="3.12")
    .apt_install("chromium", "chromium-driver")
    .pip_install("selenium>=4.30.0", "google-genai>=1.0.0", "fastapi[standard]")
    .run_function(_scrape_all)  # scrape during build; result baked into image
)

app = modal.App("dataroots-qna-bot", image=image)


SYSTEM_INSTRUCTION = (
    "You are a question-answering bot for Dataroots. You answer ONLY using the "
    "KNOWLEDGE BASE provided in the user message.\n"
    "Rules:\n"
    "- Answer concisely and to the point, with no padding or preamble.\n"
    "- Ground every answer strictly in the KNOWLEDGE BASE. Never use outside "
    "knowledge and never guess.\n"
    "- If the answer is not contained in the KNOWLEDGE BASE, reply with EXACTLY "
    f"this text and nothing else:\n{FALLBACK}"
)


def _answer(query: str) -> str:
    """Core QnA logic, shared by the JSON endpoint and the web UI."""
    from google import genai
    from google.genai import types

    query = (query or "").strip()
    if not query:
        return FALLBACK

    with open(KB_PATH, encoding="utf-8") as f:
        kb = f.read()

    client = genai.Client(api_key=os.environ["GEMINI_API_KEY"])
    resp = client.models.generate_content(
        model=MODEL,
        contents=f"KNOWLEDGE BASE:\n{kb}\n\nQUESTION: {query}",
        config=types.GenerateContentConfig(
            system_instruction=SYSTEM_INSTRUCTION,
            temperature=0,  # deterministic, no creative drift
        ),
    )
    return (resp.text or "").strip() or FALLBACK


# --- Official submission endpoint: GET ?query=... -> {"answer": "..."} ---------
@app.function(secrets=[modal.Secret.from_name("gemini")])
@modal.fastapi_endpoint(method="GET")
def answer(query: str = ""):
    return {"answer": _answer(query)}


# --- Bonus: a small hosted web UI, served from the same app --------------------
@app.function(secrets=[modal.Secret.from_name("gemini")])
@modal.asgi_app()
def web():
    from fastapi import FastAPI
    from fastapi.responses import HTMLResponse

    api = FastAPI()

    @api.get("/ask")
    def ask(query: str = ""):
        return {"answer": _answer(query)}

    @api.get("/", response_class=HTMLResponse)
    def home():
        return HTML_PAGE

    return api


